-- ============================================
-- Legislacao full-site: cleitinho / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2023-2026
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/6337/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = cleitinho-senado-completo-autoria-substantiva-2023-2026-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2023_2026_20260506
--
-- Filtro factual: endpoint senador/6337/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=6337
--   com NumOrdemAutor=1. Resultado deste snapshot: 185 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'cleitinho';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'cleitinho: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'cleitinho-senado-completo-autoria-substantiva-2023-2026-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('159095', '160083', '160933', '161820', '155797', '156252', '156255', '156256', '156257', '156258', '156372', '156447', '156920', '156922', '156923', '157020', '157021', '157022', '157023', '157068', '157141', '157330', '157331', '157449', '157451', '157830', '157858', '157907', '158329', '158368', '158369', '158370', '158372', '158373', '158374', '158489', '158490', '158491', '158499', '158500', '158569', '158597', '158598', '158599', '158600', '158601', '158712', '158747', '158748', '158750', '158753', '158833', '158834', '158857', '158877', '158938', '158939', '158940', '158941', '158981', '158982', '158984', '159330', '159523', '159524', '159591', '159642', '159643', '159787', '159891', '159898', '159899', '159909', '159910', '159942', '159988', '160308', '160309', '160310', '160669', '160670', '160671', '160672', '160673', '160744', '160855', '160856', '160926', '160927', '160975', '161481', '161726', '161727', '158596', '158922', '158937', '160013', '155879', '158008', '161942', '166348', '166631', '161879', '161880', '162428', '162490', '162494', '162495', '162779', '162780', '163007', '163309', '163323', '163345', '163944', '164284', '164285', '164362', '164363', '164681', '164890', '165416', '165534', '165535', '165556', '165569', '165618', '165714', '165945', '165946', '161878', '162503', '167055', '171789', '167181', '171933', '167039', '167040', '167041', '167051', '167052', '167060', '167061', '167189', '167190', '167203', '167507', '167693', '167731', '167732', '168006', '168299', '168428', '168429', '168465', '168466', '168468', '168469', '168645', '168890', '169007', '169366', '169513', '169685', '170145', '170732', '170733', '171222', '171410', '171623', '171627', '172037', '172142', '167779', '169849', '172217', '172561', '172562', '172564', '172565', '172907', '172908', '172909', '172563', '173126');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('159095', '160083', '160933', '161820', '155797', '156252', '156255', '156256', '156257', '156258', '156372', '156447', '156920', '156922', '156923', '157020', '157021', '157022', '157023', '157068', '157141', '157330', '157331', '157449', '157451', '157830', '157858', '157907', '158329', '158368', '158369', '158370', '158372', '158373', '158374', '158489', '158490', '158491', '158499', '158500', '158569', '158597', '158598', '158599', '158600', '158601', '158712', '158747', '158748', '158750', '158753', '158833', '158834', '158857', '158877', '158938', '158939', '158940', '158941', '158981', '158982', '158984', '159330', '159523', '159524', '159591', '159642', '159643', '159787', '159891', '159898', '159899', '159909', '159910', '159942', '159988', '160308', '160309', '160310', '160669', '160670', '160671', '160672', '160673', '160744', '160855', '160856', '160926', '160927', '160975', '161481', '161726', '161727', '158596', '158922', '158937', '160013', '155879', '158008', '161942', '166348', '166631', '161879', '161880', '162428', '162490', '162494', '162495', '162779', '162780', '163007', '163309', '163323', '163345', '163944', '164284', '164285', '164362', '164363', '164681', '164890', '165416', '165534', '165535', '165556', '165569', '165618', '165714', '165945', '165946', '161878', '162503', '167055', '171789', '167181', '171933', '167039', '167040', '167041', '167051', '167052', '167060', '167061', '167189', '167190', '167203', '167507', '167693', '167731', '167732', '168006', '168299', '168428', '168429', '168465', '168466', '168468', '168469', '168645', '168890', '169007', '169366', '169513', '169685', '170145', '170732', '170733', '171222', '171410', '171623', '171627', '172037', '172142', '167779', '169849', '172217', '172561', '172562', '172564', '172565', '172907', '172908', '172909', '172563', '173126')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'cleitinho-senado-completo-autoria-substantiva-2023-2026-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao cleitinho: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'MG'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2026
    AND COALESCE(hp.periodo_fim, 9999) >= 2023;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao cleitinho: mandato Senado/MG 2023-2026 nao encontrado em historico_politico';
  END IF;
END $$;

