DO $$
DECLARE
  cand_id uuid;
  uncovered_year_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'cleitinho';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'cleitinho: validacao de mandato Senado pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(DISTINCT seed.ano) INTO uncovered_year_count
  FROM _seed_cleitinho_senado_lote_a_projetos seed
  WHERE NOT EXISTS (
    SELECT 1
    FROM historico_politico hp
    WHERE hp.candidato_id = cand_id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND UPPER(COALESCE(hp.estado, '')) = 'MG'
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
  );

  IF uncovered_year_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao cleitinho: existem % anos de proposicoes Senado sem cobertura em mandato Senado/MG', uncovered_year_count;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'cleitinho'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_cleitinho_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'cleitinho';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'cleitinho: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('159095', '160083', '160933', '161820', '155797', '156252', '156255', '156256', '156257', '156258', '156372', '156447', '156920', '156922', '156923', '157020', '157021', '157022', '157023', '157068', '157141', '157330', '157331', '157449', '157451', '157830', '157858', '157907', '158329', '158368', '158369', '158370', '158372', '158373', '158374', '158489', '158490', '158491', '158499', '158500', '158569', '158597', '158598', '158599', '158600', '158601', '158712', '158747', '158748', '158750', '158753', '158833', '158834', '158857', '158877', '158938', '158939', '158940', '158941', '158981', '158982', '158984', '159330', '159523', '159524', '159591', '159642', '159643', '159787', '159891', '159898', '159899', '159909', '159910', '159942', '159988', '160308', '160309', '160310', '160669', '160670', '160671', '160672', '160673', '160744', '160855', '160856', '160926', '160927', '160975', '161481', '161726', '161727', '158596', '158922', '158937', '160013', '155879', '158008', '161942', '166348', '166631', '161879', '161880', '162428', '162490', '162494', '162495', '162779', '162780', '163007', '163309', '163323', '163345', '163944', '164284', '164285', '164362', '164363', '164681', '164890', '165416', '165534', '165535', '165556', '165569', '165618', '165714', '165945', '165946', '161878', '162503', '167055', '171789', '167181', '171933', '167039', '167040', '167041', '167051', '167052', '167060', '167061', '167189', '167190', '167203', '167507', '167693', '167731', '167732', '168006', '168299', '168428', '168429', '168465', '168466', '168468', '168469', '168645', '168890', '169007', '169366', '169513', '169685', '170145', '170732', '170733', '171222', '171410', '171623', '171627', '172037', '172142', '167779', '169849', '172217', '172561', '172562', '172564', '172565', '172907', '172908', '172909', '172563', '173126');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'cleitinho-senado-completo-autoria-substantiva-2023-2026-20260506'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2023_2026_20260506';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 185 THEN
    RAISE EXCEPTION 'Pos-apply cleitinho: esperadas 185 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF scope_count <> 185 THEN
    RAISE EXCEPTION 'Pos-apply cleitinho: esperadas 185 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply cleitinho: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply cleitinho Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
